 69	/****************************************************************************
 70	 * Name: host_gpiochip_direction
 71	 *
 72	 * Description:
 73	 *   Provide gpiochip pin direction config.
 74	 *
 75	 * Input Parameters:
 76	 *   priv  - A pointer to instance of Linux gpiochip.
 77	 *   pin   - The pin number.
 78	 *   input - The direction of the pin.
 79	 *
 80	 * Returned Value:
 81	 *   0 for success, other for fail.
 82	 ****************************************************************************/
 83	
 84	int host_gpiochip_direction(struct host_gpiochip_dev *priv, uint8_t pin,
 85	                            bool input)
 86	{
 87	  struct gpio_v2_line_request req;
 88	  int nonblock = 1;
 89	  int ret;
 90	
 91	  memset(&req, 0, sizeof(req));
 92	  req.num_lines = 1;
 93	  req.offsets[0] = pin;
 94	
 95	  if (priv->line_fd[pin] > 0)
 96	    {
 97	      close(priv->line_fd[pin]);
 98	      priv->line_fd[pin] = -1;
 99	    }
100	
101	  if (input)
102	    {
103	      req.config.flags = GPIO_V2_LINE_FLAG_INPUT;
104	    }
105	  else
106	    {
107	      req.config.flags = GPIO_V2_LINE_FLAG_OUTPUT;
108	    }
109	
110	  snprintf(req.consumer, sizeof(req.consumer) - 1, "gpio%d", pin);
111	  ret = host_uninterruptible(ioctl, priv->file, GPIO_V2_GET_LINE_IOCTL,
112	                             &req);
113	  if (ret < 0)
114	    {
115	      gpioerr("ERROR: pin %d set direction failed\n", pin);
116	      return -errno;
117	    }
118	
119	  ret = host_uninterruptible(ioctl, req.fd, FIONBIO, &nonblock);
120	  if (ret < 0)
121	    {
122	      gpioerr("ERROR: Failed to set non-blocking: %s\n", strerror(errno));
123	      return -errno;
124	    }
125	
126	  priv->line_fd[pin] = req.fd;
127	
128	  return 0;
129	}
