/****************************************************************************
 * Name: host_gpiochip_direction
 *
 * Description:
 *   Provide gpiochip pin direction config.
 *
 * Input Parameters:
 *   priv  - A pointer to instance of Linux gpiochip.
 *   pin   - The pin number.
 *   input - The direction of the pin.
 *
 * Returned Value:
 *   0 for success, other for fail.
 ****************************************************************************/

int host_gpiochip_direction(struct host_gpiochip_dev *priv, uint8_t pin,
                            bool input)
{
  struct gpio_v2_line_request req;
  struct gpio_v2_line_info info;
  int nonblock = 1;
  int ret;

  memset(&req, 0, sizeof(req));
  req.num_lines = 1;
  req.offsets[0] = pin;

  /* Check current line info to avoid reconfiguration conflicts */

  memset(&info, 0, sizeof(info));
  info.offset = pin;
  ret = host_uninterruptible(ioctl, priv->file, GPIO_V2_GET_LINEINFO_IOCTL,
                             &info);
  if (ret < 0)
    {
      gpioerr("ERROR: Failed to get line info for pin %d: %s\n",
              pin, strerror(errno));
      return -errno;
    }

  /* If the line is already configured with the same direction and consumer,
   * we can avoid reconfiguration
   */

  if (priv->line_fd[pin] > 0)
    {
      bool same_direction = false;

      if (input && (info.flags & GPIO_V2_LINE_FLAG_INPUT))
        {
          same_direction = true;
        }
      else if (!input && (info.flags & GPIO_V2_LINE_FLAG_OUTPUT))
        {
          same_direction = true;
        }

      if (same_direction)
        {
          /* Line is already configured with the same direction, no need to reconfigure */
          return 0;
        }

      /* Close the existing file descriptor before reconfiguration */
      close(priv->line_fd[pin]);
      priv->line_fd[pin] = -1;
    }

  if (input)
    {
      req.config.flags = GPIO_V2_LINE_FLAG_INPUT;
    }
  else
    {
      req.config.flags = GPIO_V2_LINE_FLAG_OUTPUT;
    }

  snprintf(req.consumer, sizeof(req.consumer) - 1, "gpio%d", pin);
  ret = host_uninterruptible(ioctl, priv->file, GPIO_V2_GET_LINE_IOCTL,
                             &req);
  if (ret < 0)
    {
      gpioerr("ERROR: pin %d set direction failed\n", pin);
      return -errno;
    }

  ret = host_uninterruptible(ioctl, req.fd, FIONBIO, &nonblock);
  if (ret < 0)
    {
      gpioerr("ERROR: Failed to set non-blocking: %s\n", strerror(errno));
      return -errno;
    }

  priv->line_fd[pin] = req.fd;

  return 0;
}

